import { SolidComponent } from '@/type';
import { cn } from '@/utils/cn';
import { Component } from 'solid-js';

type SwapType = {
  item1: SolidComponent;
  item2: SolidComponent;
  effect?: 'rotate' | 'flip' | 'none';
  onChange?: (value: boolean) => void;
};
export const Swap: Component<SwapType> = p => {
  return (
    <label
      class={cn(
        'swap',
        p.effect === 'flip' ? 'swap-flip' : p.effect === 'rotate' ? 'swap-rotate' : '',
      )}
    >
      <input
        type="checkbox"
        onChange={e => {
          p?.onChange?.(e.target.checked);
        }}
      />
      <div class="swap-on">{p.item1 as Element}</div>
      <div class="swap-off">{p.item2 as Element}</div>
      <div class="swap-indeterminate"></div>
    </label>
  );
};
